public boolean isPangram(String sentence) {
    boolean[] alphabet = new boolean[26];
    for (char c : sentence.toCharArray()) {
        alphabet[c - 'a'] = true;
    }
    for (boolean flag : alphabet) {
        if (!flag) return false;
    }
    return true;
}
```

